/**
 * @name textarea
 * @description Displays a form textarea or a component that looks like a textarea.
 * @dependencies none
 * @type registry:ui
 */
import * as React from "react";

import { cn } from "@/lib/utils";
import { useAutoSpace } from "@/hooks/use-auto-space";

function Textarea({
  className,
  autoSpace = false,
  ...props
}: React.ComponentProps<"textarea"> & {
  /**
   * When `true`, automatically inserts a space after punctuation (. , ! ? ; :)
   * when the user types the next word without one.
   */
  autoSpace?: boolean;
}) {
  const handleBeforeInput = useAutoSpace(autoSpace);

  return (
    <textarea
      data-slot="textarea"
      className={cn(
        "border-input dark:bg-input/30 focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:aria-invalid:border-destructive/50 placeholder:text-placeholder-foreground flex field-sizing-content min-h-16 w-full rounded-md border bg-transparent px-2.5 py-2 text-base shadow-xs transition-[color,box-shadow] outline-none focus-visible:ring-[3px] disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:ring-[3px] md:text-sm",
        className
      )}
      onBeforeInput={handleBeforeInput}
      {...props}
    />
  );
}

export { Textarea };
